commands.cmd:
raw=$(cat /sys/fs/cgroup/cpu.stat) || { echo "cpu.stat unreadable" >&2; exit 1; }
printf '%s\n' "$raw" | awk '
  /^nr_periods /{p=$2}
  /^nr_throttled /{t=$2}
  /^throttled_usec /{u=$2}
  END{
    if (p=="") { print "nr_periods missing" > "/dev/stderr"; exit 1 }
    printf "{\"nr_periods\":%d,\"nr_throttled\":%d,\"throttled_usec\":%d,\"throttled_pct\":\"%.2f\"}",
      p, t, u, (p>0 ? t/p*100 : 0)
  }' || exit 1
